INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('judicial-cf446b4c-moex-00164', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲男乙女於民國110年2月14日結婚。甲乙未約定夫妻財產制，乙於婚後無勞力所得，專心在 家操持家務。關於婚姻普通效力及夫妻財產之規定，下列敘述，何者正確？ 甲乙對於其婚前財產，互負報告之義務。於家庭生活費用外，甲乙應協議一定數額之金錢，供 乙自由處分 甲如依法應給付家庭生活費用而不給付時，法院因乙之請求，得宣告改用分別財產制 甲乙之住所，由雙方共同協議之；未為協議或協議不成時，於戶政事務所抽籤決定之 甲乙係以聯合財產制為其法定夫妻財產制，財產應共同管理、使用及收益', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 20, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00165', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '40歲之養父甲與17歲之養子乙，合意終止收養關係。其收養關係自何時終止？ 合意時    書面成立時 法院認可裁定確定時  法定代理人同意時', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00166', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲為未成年人，與父乙、母丙、姊丁（已成年）共同居住於臺北市。乙之父戊居住於花蓮。某日 乙、丙遭遇車禍，同時死亡。下列何者為甲之監護人？ 法院選定之人  戊  丁  臺北市社會局', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00167', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '甲男中年喪偶。甲有二子乙、丙、一女丁；乙與丙均未婚。丁已婚，丁夫為戊，丁戊有一子為庚。 丁於民國（下同）111年1月間死亡。甲於111年12月間死亡。甲未立遺囑。甲有遺產新臺幣（下 同）1200萬元，無債務。關於甲遺產之繼承，下列敘述，何者正確？ 乙繼承400萬元  丙繼承300萬元  庚繼承200萬元  戊繼承150萬元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 23, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00168', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於甲於2024年1月1日所立遺囑之效力敘述，何者正確？ 甲為2005年12月31日出生，其遺囑無效 甲為2008年12月31日出生，其遺囑有效 甲為2007年5月31日出生，所立遺囑未經其法定代理人同意，其遺囑無效 甲為2007年12月31日出生，其法定代理人拒絕承認甲所立遺囑，其遺囑無效', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 24, "answer_corrected": true, "flags": ["answer_corrected_skip_v1", "incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00169', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-113-a7c7609b', 'sub-judicial-cf446b4c-04', NULL, 'single_choice', '下列關於特留分之敘述，何者正確？ 繼承人喪失繼承權，但仍享有特留分 繼承開始後，特留分權利不得自由拋棄 拋棄特留分，不等於拋棄繼承 拋棄特留分後，其他特留分權利人之特留分當然因而增加', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "00de5652f9d0", "answer_pdf_sha1": "bda7d653402b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "203", "s": "0404", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 25, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00170', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者屬刑法第17條規定的加重結果犯？', '["警察追捕不接受酒駕臨檢的駕駛人，卻導致警車自撞分隔島，員警受傷", "小偷偷走被害人背包，背包中除了錢財外，尚有氣喘藥，後被害人因氣喘發作，藥物被小偷偷走未能及 時服藥而死亡", "駕駛因粗心闖紅燈，雖及時煞車未撞到行人，行人卻因驚嚇而心肌梗塞死亡", "原想給情敵一個教訓，卻在毆打情敵時不小心打到要害而導致情敵傷重死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00171', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何種非基於正當目的之接合行為，不該當刑法上之性交？', '["以手指與他人肛門接合", "以雨傘插入他人性器", "以酒瓶插入他人口腔", "以口腔與他人性器接合"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00172', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '下列何者不適用刑法第2條第1項所揭示的從舊從輕原則？', '["有期徒刑", "褫奪公權", "罰金", "沒收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL),
  ('judicial-cf446b4c-moex-00173', 'judicial-cf446b4c', 'judicial-cf446b4c-moex-112-e2754278', 'sub-judicial-cf446b4c-01', NULL, 'single_choice', '有關「法律明確性原則」或「犯罪構成要件明確性」，下列敘述何者錯誤？', '["刑罰之構成要件應以法律定之，只要法律就其構成要件授權以命令為補充規定，必然違反刑罰明確性原 則而違憲", "犯罪構成要件雖有不確定性，但只要意義並非一般人難以理解、且為受規範者所得預見，並可經由司法 審查加以確認，即不違背犯罪構成要件明確性原則", "犯罪構成要件明確性原則是罪刑法定原則內涵之一", "民國98年1月廢除之檢肅流氓條例有關「欺壓善良」、「品行惡劣」、「遊蕩無賴」等流氓之定義規定， 經司法院解釋認為違反法律明確性原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:22+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "204", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "執達員"}'::jsonb, NULL)
